  return (h + 2*p - k) // s + 1`,example:"out_size(32, 3, 1, 2) → 16.",trap:"Dilated convolution uses effective kernel size."})},{id:"im2col-note-conv",label:"im2col / GEMM",tooltip:e({short:"Efficient implementations reshape patches into matrix multiply.",intuition:"Same math, faster hardware utilization.",code:"# Conceptual: patches_matrix @ kernel_matrix",example:"cuDNN uses optimized conv algorithms transparently.",trap:"Memory spikes on im2col for huge feature maps."})}]},{id:"traps",label:"Common traps",type:"trap",children:[{id:"dense-per-patch-trap-conv",label:"Not dense per patch",tooltip:e({short:"Same kernel everywhere—unlike unique weights per location.",intuition:"Dense layer on flattened patches explodes parameter count.",example:"224×224 RGB → impractical fully connected first layer.",trap:"1×1 conv is dense across channels, still shared spatially."})},{id:"shape-mismatch-conv",label:"Shape mismatch",tooltip:e({short:"in_channels must match previous layer out_channels.",intuition:"Conv weight depth dimension must align.",example:"Conv 3→16 then Conv 16→32 is valid; 3→32 after 16 is not.",trap:"Transposed conv upsampling has its own shape rules."})},{id:"padding-mode-trap-conv",label:"Padding mode",tooltip:e({short:"valid vs same vs explicit pad changes borders.",intuition:"Edge pixels participate in fewer products without padding.",example:"Corner output uses partial patch in valid conv.",trap:"Asymmetric pad breaks center alignment assumptions."})},{id:"correlation-vs-conv-trap",label:"Correlation vs convolution",tooltip:e({short:"ML “conv” often means cross-correlation (no kernel flip).",intuition:"Learned kernels adapt regardless of naming.",example:"PyTorch Conv2d correlates by default.",trap:"Signal-processing convolution flips the kernel."})},{id:"dilation-stride-trap-conv",label:"Stride vs dilation",tooltip:e({short:"Stride subsamples outputs; dilation spaces kernel taps.",intuition:"Both enlarge receptive field differently.",example:"dilation=